import{_ as o,a as e,b as t,c as n}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as d,o as r,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"Magnet transfer","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Other/magnet-transfer.md","filePath":"cs-CZ/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"cs-CZ/Other/magnet-transfer.md"};function p(u,a,h,m,v,k){return r(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="magnet-transfer" tabindex="-1">Magnet transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet transfer&quot;">​</a></h1><p>Magnet transfer stáhne soubory z magnet odkazu a automaticky je nahraje do vybraného cloudového kanálu.</p><p>Hodí se pro přesun anime epizod, videí, archivů a podobných souborů. Vložíte magnet odkaz a ImgBed vytvoří úlohu stahování na pozadí. Po dokončení stahování se soubor nahraje do ImgBed a finální odkaz se objeví v seznamu uploadů.</p><p><img src="'+o+'" alt="Magnet transfer" loading="lazy"></p><h2 id="kde-pouzit" tabindex="-1">Kde použít <a class="header-anchor" href="#kde-pouzit" aria-label="Permalink to &quot;Kde použít&quot;">​</a></h2><p>Vstup Magnet transferu je v upload části domovské stránky.</p><p>Vložte magnet odkaz do pole, vyberte <code>Transfer</code> a nahrajte.</p><p><img src="'+e+'" alt="Upload anime" loading="lazy"></p><h2 id="pred-prvnim-pouzitim" tabindex="-1">Před prvním použitím <a class="header-anchor" href="#pred-prvnim-pouzitim" aria-label="Permalink to &quot;Před prvním použitím&quot;">​</a></h2><p>Nejprve nastavte Magnet transfer v administraci.</p><p>Obvykle potřebujete:</p><ol><li>GitHub účet pro spuštění stahovací úlohy.</li><li>Cloudový upload kanál, například Google Drive nebo OneDrive.</li><li>Cílový upload adresář.</li><li>Timeout úlohy.</li></ol><p>Po připravení nastavení se vraťte na domovskou stránku a vložte magnet odkaz pro spuštění transferu.</p><h2 id="nahrani-magnet-odkazu" tabindex="-1">Nahrání magnet odkazu <a class="header-anchor" href="#nahrani-magnet-odkazu" aria-label="Permalink to &quot;Nahrání magnet odkazu&quot;">​</a></h2><ol><li>Vložte magnet odkaz do upload pole na domovské stránce.</li><li>Ověřte, že je režim nastavený na <code>Transfer</code>.</li><li>Klikněte na upload.</li><li>Počkejte, než ImgBed vytvoří magnet úlohu.</li><li>Po spuštění úlohy sledujte postup v plovoucím panelu <code>Magnet Tasks</code> vpravo dole.</li></ol><p>Stahování a upload mohou trvat. Rychlost závisí na magnet zdroji, runtime prostředí GitHub a zvoleném cloudovém kanálu.</p><p><img src="'+t+'" alt="Stahování magnetu" loading="lazy"></p><h2 id="po-dokonceni" tabindex="-1">Po dokončení <a class="header-anchor" href="#po-dokonceni" aria-label="Permalink to &quot;Po dokončení&quot;">​</a></h2><p>Po dokončení úlohy seznam uploadů ukáže název souboru a odkaz.</p><p>Videa zobrazují video náhled, obrázky náhled obrázku a ostatní soubory běžnou ikonu souboru.</p><p><img src="'+n+'" alt="Stažené video" loading="lazy"></p><p>Můžete zkopírovat:</p><table tabindex="0"><thead><tr><th>Typ odkazu</th><th>Použití</th></tr></thead><tbody><tr><td>Původní odkaz</td><td>Přímý přístup k souboru</td></tr><tr><td>Markdown</td><td>Markdown příspěvky nebo poznámky</td></tr><tr><td>HTML</td><td>Kód webové stránky</td></tr><tr><td>BBCode</td><td>Fóra podporující BBCode</td></tr></tbody></table><h2 id="panel-magnet-uloh" tabindex="-1">Panel magnet úloh <a class="header-anchor" href="#panel-magnet-uloh" aria-label="Permalink to &quot;Panel magnet úloh&quot;">​</a></h2><p>Panel vpravo dole ukazuje počet úloh, název úlohy, průběh a finální stav.</p><p>Běžné stavy:</p><table tabindex="0"><thead><tr><th>Stav</th><th>Význam</th></tr></thead><tbody><tr><td>Waiting</td><td>Úloha je vytvořená a čeká na spuštění.</td></tr><tr><td>Downloading</td><td>Magnet zdroj se stahuje.</td></tr><tr><td>Uploading</td><td>Soubor je stažený a nahrává se do cloudového úložiště.</td></tr><tr><td>Completed</td><td>Upload byl úspěšný a odkaz lze zkopírovat.</td></tr><tr><td>Failed</td><td>Úloha se nedokončila úspěšně. Zkontrolujte zprávu a zkuste to znovu.</td></tr></tbody></table><h2 id="tipy" tabindex="-1">Tipy <a class="header-anchor" href="#tipy" aria-label="Permalink to &quot;Tipy&quot;">​</a></h2><ul><li>Pokud magnet odkaz obsahuje více souborů, ImgBed pro zobrazení upřednostní hlavní dokončený soubor.</li><li>Velké soubory trvají déle. Před obnovením stránky počkejte na dokončení úlohy.</li><li>Pokud magnet zdroj nemá dostupné peery, může být velmi pomalý nebo selhat.</li><li>Pokud cloudový účet nemá místo, autorizace vypršela nebo je upload adresář špatný, úloha může selhat.</li><li>Náhled videa může po dokončení uploadu trvat několik sekund.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="po-vlozeni-magnet-odkazu-se-nic-nespusti" tabindex="-1">Po vložení magnet odkazu se nic nespustí <a class="header-anchor" href="#po-vlozeni-magnet-odkazu-se-nic-nespusti" aria-label="Permalink to &quot;Po vložení magnet odkazu se nic nespustí&quot;">​</a></h3><p>Ověřte, že je Magnet transfer zapnutý v administraci a že je vybraný použitelný GitHub účet i cloudový kanál.</p><h3 id="stahovani-je-vzdy-pomale" tabindex="-1">Stahování je vždy pomalé <a class="header-anchor" href="#stahovani-je-vzdy-pomale" aria-label="Permalink to &quot;Stahování je vždy pomalé&quot;">​</a></h3><p>Rychlost magnetu závisí na samotném zdroji. Pokud nejsou dostupní peeři, stahování může být velmi pomalé nebo nemožné.</p><h3 id="po-uploadu-se-nezobrazi-nahled" tabindex="-1">Po uploadu se nezobrazí náhled <a class="header-anchor" href="#po-uploadu-se-nezobrazi-nahled" aria-label="Permalink to &quot;Po uploadu se nezobrazí náhled&quot;">​</a></h3><p>Nejdřív ověřte, že se odkaz na soubor otevře. Video soubory mohou v prohlížeči potřebovat chvíli k načtení, případně otevřete odkaz přímo.</p><h3 id="co-zkontrolovat-kdyz-uloha-selze" tabindex="-1">Co zkontrolovat, když úloha selže? <a class="header-anchor" href="#co-zkontrolovat-kdyz-uloha-selze" aria-label="Permalink to &quot;Co zkontrolovat, když úloha selže?&quot;">​</a></h3><p>Zkontrolujte, zda je magnet odkaz platný, cloudový kanál funkční a upload adresář správný. Potom úlohu odešlete znovu.</p>',38)])])}const g=d(s,[["render",p]]);export{c as __pageData,g as default};
